#define _DEFAULT_SOURCE
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <pthread.h>

/* == EXEMPLE =======================================
 * Producteur-consommateur via pipe + threads
 * Pattern: un thread ecrit, l'autre lit, pipe entre les deux.
 * ================================================= */
typedef struct { int fd; } Endpoint;

void *producer(void *arg) {
    Endpoint *e = (Endpoint *)arg;
    for (int i = 1; i <= 3; i++) {
        char msg[32];
        int len = snprintf(msg, sizeof(msg), "item-%d", i);
        write(e->fd, msg, len);
    }
    close(e->fd);
    return NULL;
}

void *consumer(void *arg) {
    Endpoint *e = (Endpoint *)arg;
    char buf[64];
    ssize_t n;
    while ((n = read(e->fd, buf, sizeof(buf)-1)) > 0) {
        buf[n] = '\0';
        printf("Got: %s\n", buf);
    }
    return NULL;
}

void example_pipe_threads(void) {
    int fd[2]; pipe(fd);
    Endpoint wr = {fd[1]}, rd = {fd[0]};
    pthread_t t1, t2;
    pthread_create(&t1, NULL, producer, &wr);
    pthread_create(&t2, NULL, consumer, &rd);
    pthread_join(t1, NULL);
    pthread_join(t2, NULL);
    close(fd[0]);
}
